// src/hooks/test-tracker.ts
var createTestTrackerHook = ($, directory) => {
  return async (event) => {
    if (event.type === "session.idle") {
    }
    if (event.type === "tool.execute.after") {
      const data = event.data;
      if (data.tool === "bash" && data.args?.command) {
        const command = data.args.command;
        if (isTestCommand(command)) {
          await trackTestExecution($, directory, command, data.result);
        }
      }
    }
  };
};
function isTestCommand(command) {
  const testPatterns = [
    /npm\s+test/,
    /pnpm\s+test/,
    /yarn\s+test/,
    /bun\s+test/,
    /jest/,
    /vitest/,
    /mocha/,
    /pytest/,
    /go\s+test/,
    /cargo\s+test/
  ];
  return testPatterns.some((pattern) => pattern.test(command));
}
async function trackTestExecution($, directory, command, result) {
  try {
    const mappingPath = `${directory}/.tdd/test-mapping.json`;
    let mapping;
    try {
      const content = await $`cat ${mappingPath}`.text();
      mapping = JSON.parse(content);
    } catch {
      mapping = { version: "1.0.0", mappings: {}, history: [] };
    }
    if (!mapping.history) {
      mapping.history = [];
    }
    mapping.history.push({
      timestamp: (/* @__PURE__ */ new Date()).toISOString(),
      command,
      passed: result ? !result.includes("FAIL") : void 0
    });
    if (mapping.history.length > 100) {
      mapping.history = mapping.history.slice(-100);
    }
    await $`echo ${JSON.stringify(mapping, null, 2)} > ${mappingPath}`;
  } catch {
  }
}

// src/hooks/state-persist.ts
var createStatePersistHook = ($, directory) => {
  return async (event) => {
    if (event.type === "session.idle" || event.type === "session.deleted") {
      await persistState($, directory);
    }
    if (event.type === "session.error") {
      await persistState($, directory, true);
    }
  };
};
async function persistState($, directory, isError = false) {
  try {
    const statePath = `${directory}/.tdd/state.json`;
    try {
      await $`test -f ${statePath}`;
    } catch {
      return;
    }
    const content = await $`cat ${statePath}`.text();
    const state = JSON.parse(content);
    state.updated_at = (/* @__PURE__ */ new Date()).toISOString();
    if (isError && state.workflow_phase === "actor_working") {
      state.workflow_phase = "in_progress";
      state.last_error = (/* @__PURE__ */ new Date()).toISOString();
    }
    await $`echo ${JSON.stringify(state, null, 2)} > ${statePath}`;
    const backupPath = `${directory}/.tdd/state.backup.json`;
    await $`cp ${statePath} ${backupPath}`;
  } catch {
  }
}

